import{_ as t,c as a,o as i,ak as n,ao as o}from"./chunks/framework.DHLlVITf.js";const m=JSON.parse('{"title":"AireGlu Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireglu-v1-117-0.md","filePath":"aireblock-releases/aireglu-v1-117-0.md","lastUpdated":1783350342000}'),s={name:"aireblock-releases/aireglu-v1-117-0.md"};function l(r,e,d,c,p,h){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="aireglu-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+o+'"> AireGlu Release Notes</span> <a class="header-anchor" href="#aireglu-release-notes" aria-label="Permalink to “AireGlu Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 1.117.0<br><strong>Release Date:</strong> May 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Disable Individual Tasks Within an Endpoint Pipeline — GLU-299</li><li>Hide Git-Synchronised Endpoints from the Endpoints List — GLU-1536</li><li>Add New Client Connections — GLU-3099</li><li>Open Endpoints in a New Browser Tab — GLU-2856</li></ul><h4 id="⚡-improvements" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements" aria-label="Permalink to “⚡ Improvements”">​</a></h4><ul><li>Email Task Authentication Moved to a Dedicated Tab — GLU-3096</li><li>Delete and Audit Support for Connections — GLU-3113</li></ul><h4 id="🔒-security-updates" tabindex="-1">🔒 Security Updates <a class="header-anchor" href="#🔒-security-updates" aria-label="Permalink to “🔒 Security Updates”">​</a></h4><ul><li>Various security updates and patches</li></ul><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="disable-individual-tasks-within-an-endpoint-pipeline-glu-299" tabindex="-1">Disable Individual Tasks Within an Endpoint Pipeline (GLU-299) <a class="header-anchor" href="#disable-individual-tasks-within-an-endpoint-pipeline-glu-299" aria-label="Permalink to “Disable Individual Tasks Within an Endpoint Pipeline (GLU-299)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A toggle has been added to each task in the endpoint pipeline editor, allowing individual tasks to be enabled or disabled. Disabled tasks are visually greyed out and are skipped at runtime. Usage data will reflect that a task was disabled rather than executed, consistent with tasks skipped by filters.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now turn off specific steps in an endpoint pipeline without removing them entirely. This makes it easier to test, debug, or temporarily bypass a task without losing its configuration.</p></div><h4 id="hide-git-synchronised-endpoints-from-the-endpoints-list-glu-1536" tabindex="-1">Hide Git-Synchronised Endpoints from the Endpoints List (GLU-1536) <a class="header-anchor" href="#hide-git-synchronised-endpoints-from-the-endpoints-list-glu-1536" aria-label="Permalink to “Hide Git-Synchronised Endpoints from the Endpoints List (GLU-1536)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A toggle has been added to the endpoints list allowing users to show or hide git-synchronised endpoints. All endpoints are shown by default, and the user&#39;s preference is persisted consistently with other UI toggles such as the Group View option.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>If your environment contains many repository-synchronised endpoints that you don&#39;t need to interact with directly, you can now hide them to focus on the endpoints you actively configure. The toggle is easy to switch whenever you need to view synchronised endpoints again.</p></div><h4 id="add-new-client-connections-glu-3099" tabindex="-1">Add New Client Connections (GLU-3099) <a class="header-anchor" href="#add-new-client-connections-glu-3099" aria-label="Permalink to “Add New Client Connections (GLU-3099)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A new Connections framework has been introduced, providing a unified place to create and manage different connection types — including OAuth and Office 365 email connections. The Connections page now features an &quot;Add Connection&quot; dialogue that presents available connection types and guides configuration. Existing OAuth connections have been migrated into this new framework, and support for deleting connections has also been added.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now manage all your integration connections in one place, with a consistent experience for adding, editing, and removing them. The framework is built to support additional connection types — such as Gmail — in future releases, and tasks will automatically surface only the connection types relevant to them.</p></div><h4 id="open-endpoints-in-a-new-browser-tab-glu-2856" tabindex="-1">Open Endpoints in a New Browser Tab (GLU-2856) <a class="header-anchor" href="#open-endpoints-in-a-new-browser-tab-glu-2856" aria-label="Permalink to “Open Endpoints in a New Browser Tab (GLU-2856)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Endpoints can now be opened in a new browser tab using middle-click or right-click and selecting &quot;Open in new tab&quot;, following standard browser conventions.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now work with multiple endpoints side by side without losing your place in the endpoints list. No more navigating back and forth to compare or edit several endpoints at once.</p></div><h3 id="⚡-improvements-1" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements-1" aria-label="Permalink to “⚡ Improvements”">​</a></h3><hr><h4 id="email-task-authentication-moved-to-a-dedicated-tab-glu-3096" tabindex="-1">Email Task Authentication Moved to a Dedicated Tab (GLU-3096) <a class="header-anchor" href="#email-task-authentication-moved-to-a-dedicated-tab-glu-3096" aria-label="Permalink to “Email Task Authentication Moved to a Dedicated Tab (GLU-3096)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>SMTP settings within the email task have been moved to a dedicated Authentication tab. The authentication method dropdown now offers clearer options: default SMTP settings, custom SMTP settings, or a named connection (for future use).</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Email task configuration is now better organised, making it easier to find and manage authentication settings. The cleaner layout also prepares the way for linking email tasks directly to named connections in a future release.</p></div><h4 id="delete-and-audit-support-for-connections-glu-3113" tabindex="-1">Delete and Audit Support for Connections (GLU-3113) <a class="header-anchor" href="#delete-and-audit-support-for-connections-glu-3113" aria-label="Permalink to “Delete and Audit Support for Connections (GLU-3113)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Support for deleting connections has been added to both the API and the Connections page UI, allowing connections that are no longer needed to be removed cleanly from the system.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now remove connections that are no longer in use, keeping your Connections page tidy and reducing clutter when selecting connections within tasks.</p></div>',33)])])}const b=t(s,[["render",l]]);export{m as __pageData,b as default};
